  ('heelevel3-d1056197-moex-00096', 'heelevel3-d1056197', 'heelevel3-d1056197-moex-111-d3ff7f6b', 'sub-heelevel3-d1056197-04', NULL, 'single_choice', '假設經濟體系中有兩位消費者（A 和 B），兩種財貨（X 和 Y）。消費者 A 的初始稟賦為 （X=30,Y=20）而消費者 B的初始稟賦為（X=20,Y=30）。兩位消費者的效用函數皆為 U（X,Y）=X0.5Y0.5。均衡時兩位消費者的消費數量為何？', '["A（X=30,Y=20），B（X=20,Y=30）", "A（X=26,Y=24），B（X=24,Y=26）", "A（X=25,Y=25），B（X=25,Y=25）", "A（X=20,Y=30），B（X=30,Y=20）"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:51+00:00", "source_pdf_sha1": "7b2be102255d", "answer_pdf_sha1": "40ea3bc8eedf", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "330", "s": "0908", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "經濟學", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "僑務行政"}'::jsonb, NULL),
